  1→import { useState, useCallback, useEffect } from 'react';
  2→import useMentionAutocomplete from './useMentionAutocomplete';
  3→
  4→const MENTION_REGEX = /@([\w-]*)$/;
  5→
  6→const useTextareaMention = (value, setValue, textareaRef, maxLength = Infinity, excludeUserId) => {
  7→    const [cursorPos, setCursorPos] = useState(0);
  8→    const [dropdownPos, setDropdownPos] = useState({ top: 0, left: 0 });
  9→
 10→    const {
 11→        results,
 12→        selectedIndex,
 13→        setSelectedIndex,
 14→        isOpen,
 15→        query,
 16→        close,
 17→        moveUp,
 18→        moveDown,
 19→    } = useMentionAutocomplete(value, cursorPos, excludeUserId);
 20→
 21→    const updateDropdownPosition = useCallback(() => {
 22→        if (!textareaRef.current) return;
 23→        const rect = textareaRef.current.getBoundingClientRect();
 24→        setDropdownPos({
 25→            top: rect.bottom + 4,
 26→            left: rect.left,
 27→            width: rect.width,
 28→        });
 29→    }, [textareaRef]);
 30→
 31→    useEffect(() => {
 32→        if (isOpen) updateDropdownPosition();
 33→    }, [isOpen, updateDropdownPosition]);
 34→
 35→    const handleSelect = useCallback((user) => {
 36→        const username = user.username;
 37→        const textUpToCursor = value.slice(0, cursorPos);
 38→        const match = textUpToCursor.match(MENTION_REGEX);
 39→
 40→        if (!match) return;
 41→
 42→        const beforeMention = textUpToCursor.slice(0, match.index);
 43→        const afterCursor = value.slice(cursorPos);
 44→        const newValue = `${beforeMention}@${username} ${afterCursor}`;
 45→
 46→        if (newValue.length > maxLength) return;
 47→
 48→        setValue(newValue);
 49→        close();
 50→
 51→        const newCursorPos = beforeMention.length + username.length + 2;
 52→        requestAnimationFrame(() => {
 53→            if (textareaRef.current) {
 54→                textareaRef.current.focus();
 55→                textareaRef.current.setSelectionRange(newCursorPos, newCursorPos);
 56→            }
 57→        });
 58→    }, [value, cursorPos, setValue, close, textareaRef, maxLength]);
 59→
 60→    const onChange = useCallback((e) => {
 61→        setCursorPos(e.target.selectionStart || 0);
 62→    }, []);
 63→
 64→    const onKeyUp = useCallback((e) => {
 65→        if (e.isComposing) return;
 66→        setCursorPos(e.target.selectionStart || 0);
 67→    }, []);
 68→
 69→    const onKeyDown = useCallback((e) => {
 70→        if (e.isComposing) return;
 71→        if (!isOpen) return;
 72→
 73→        if (e.key === 'ArrowDown') {
 74→            e.preventDefault();
 75→            moveDown();
 76→        } else if (e.key === 'ArrowUp') {
 77→            e.preventDefault();
 78→            moveUp();
 79→        } else if (e.key === 'Enter' || e.key === 'Tab') {
 80→            if (results.length > 0) {
 81→                e.preventDefault();
 82→                handleSelect(results[selectedIndex]);
 83→            }
 84→        } else if (e.key === 'Escape') {
 85→            e.preventDefault();
