 52→
 53→    const clickProfile = handleClickProfile(navigate);
 54→
 55→    const {data, isLoading, fetchNextPage, hasNextPage, isFetchinNextPage} = useInfiniteQuery({
 56→        queryKey: ['getPostReplies', comments.id],
 57→        queryFn: ({pageParam = null, queryKey}) => getPostReplies(queryKey[1], 5, pageParam),
 58→        getNextPageParam: (lastPage) => {
 59→            if(lastPage.hasMore){
 60→                const lastReply = lastPage?.data[lastPage?.data.length - 1];
 61→                return lastReply.id;
 62→            } else{
 63→                return undefined
 64→            }
 65→        },
 66→        refetchOnWindowFocus: false,
 67→        enabled: showReplies,
 68→        staleTime: 1000 * 60 * 5
 69→    })
 70→
 71→    const handleClickReplyButton = (e) =>{
 72→        e.stopPropagation();
 73→        setShowReplyInput(!showReplyInput);
 74→    }
 75→
 76→    const handleShowMoreReplies = () => {
