 87→                    <div
 88→                        onClick={(e) => handleClickContent(e, opinion.id, user?.userData[0].id)}
 89→                        className="ov-body"
 90→                    >
 91→                        <MentionText text={opinion.opinion} />
 92→                    </div>
 93→
 94→                    <div className="ov-meta-bar">
 95→                        <span className="ov-reply-pill" onClick={(e) => { e.stopPropagation(); navigate('/home/opinionsViewer', { state: { opinionId: opinion.id, userId: opinion.user_id } }); }}>
 96→                            <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
 97→                                <path d="M21 15a2 2 0 0 1-2 2H7l-4 4V5a2 2 0 0 1 2-2h14a2 2 0 0 1 2 2z" />
 98→                            </svg>
 99→                            {opinion.reply_count || 0} {opinion.reply_count === 1 ? 'reply' : 'replies'}
100→                        </span>
101→                        <span className="ov-full-date">
102→                            {new Date(opinion.created_at).toLocaleDateString('en-US', {
103→                                month: 'long',
104→                                day: '2-digit',
105→                                year: 'numeric',
106→                            })}
107→                        </span>
108→                    </div>
109→                </motion.div>
110→            ))}
111→
112→            <div ref={ref} className="my-opinions-inview-container">
113→
114→            </div>
115→
116→        </div>
117→        </AnimatePresence>
118→        </>
119→    )
120→}
