 80→const UnreadNotification = () =>{
 81→    const {ref: inviewRef, inView} = useInView({threshold: 0.2});
 82→
 83→    const {session, user} = useAuth();
 84→    const modalRef = useRef();
 85→    const navigate = useNavigate();
 86→
 87→    const [settingsId, setSettingsId] = useState(null);
 88→
 89→    const handleClickSettings = (e, notifId) =>{
 90→        e.stopPropagation();
 91→        setSettingsId(settingsId === notifId ? null : notifId);
 92→    }
 93→
 94→    const deleteNotifMutation = useUserDeleteNotificationMutation(session);
 95→    const handleClickDeleteNotification = (e, notifId, source) =>{
 96→        e.stopPropagation();
 97→        try {
 98→            const message = deleteNotifMutation.mutateAsync({notifId, source});
 99→            if(message){
100→                // console.log(message)
101→            }
102→        } catch (error) {
103→            console.error('error deleting notification',error)
104→        }
105→    }
106→
107→    const iconArray = UNREAD_ICON_ARRAY;
108→
109→    const {data, isLoading, isFetchinNextPage, hasNextPage, fetchNextPage} = useInfiniteQuery({
110→        queryKey: ['unreadNotification', session?.user?.id],
111→        queryFn: ({pageParam = null}) => getUnreadNotification(session?.access_token, pageParam, 5),
112→        getNextPageParam: (lastPage) => {
113→            if(lastPage.hasMore){
114→                const lastJournal = lastPage?.data[lastPage?.data?.length - 1];
115→                return new Date(lastJournal.created_at).toISOString();
116→            } else {
117→                return undefined;
118→            }
119→        },
120→        enabled: !!session,
121→        refetchOnWindowFocus: false,
122→        staleTime: 1000 * 60 * 2
123→    })
124→
125→    useEffect(() => {
126→        if(inView && !isFetchinNextPage && hasNextPage){
127→            fetchNextPage();
128→        }
129→    }, [fetchNextPage, hasNextPage, isFetchinNextPage, inView])
130→
131→    const handleClickNotif = handleCLickContent(navigate);
132→    const handleClickOpinionNotif = handleClickOpinion(navigate);
133→    const mutationReadNotif = useReadNotificationMutation(session);
134→
135→    const handleReadNotif = async(e, notification) =>{
136→        const source = notification?.source || 'journal';
137→        mutationReadNotif.mutate({notifId: notification.id, source});
138→
139→        if(source === 'opinion'){
140→            handleClickOpinionNotif(e, notification?.opinions?.id, notification?.opinions?.user_id)
141→        } else {
142→            handleClickNotif(
143→                e,
144→                null,
145→                '',
146→                notification?.journals?.title,
147→                notification?.journals?.users?.id,
148→                notification?.journals?.users?.name,
149→                notification?.journals?.users?.image_url,
150→                notification?.journals?.created_at,
151→                notification?.journal_id,
152→                notification?.hasLiked,
153→                0,
154→                notification?.hasBookMarked,
155→                0,
156→                0
157→            )
158→        }
159→    }
160→
161→    const unreadNotifications = data?.pages?.flatMap((page) => page.data) || [];
162→    
163→    // useEffect(() =>{
164→    //     console.log(unreadNotifications)
165→    // }, [data])
166→
167→    useEffect(() => {
168→        const handleClickOutside = (e) =>{
169→            if(modalRef.current && !modalRef.current.contains(e.target)){
170→                setSettingsId(null);
171→            }
172→        }
173→        document.addEventListener('mousedown', handleClickOutside);
174→
175→        return() => {
176→            document.removeEventListener('mousedown', handleClickOutside)
177→        }
178→    }, [])
179→
180→    if(unreadNotifications.length === 0 && !isLoading){
181→        return(
182→            <div className='notification-loading-container'>
183→                No unread notifications availabe
184→            </div>
185→        )
186→    }
187→    if(isLoading) {
188→        return(
189→            <div className="notification-loading-container">
190→                <MoonLoader size={25} color="var(--loader-color)" loading={isLoading}/>
191→            </div>
192→        )
193→    }
194→
195→    return(
196→        <>
197→        <div className="unread-notification-component-container">
198→            {unreadNotifications?.map((unreadNotification) => {
199→                const isOpinion = unreadNotification?.source === 'opinion';
200→                const displayType = isOpinion
201→                    ? (unreadNotification?.type === 'mention' ? 'mention' : 'opinion_reply')
202→                    : unreadNotification?.type;
203→                const previewText = !isOpinion ? (unreadNotification?.journals?.preview_text || '') : '';
204→                const thumbnailUrl = !isOpinion ? (unreadNotification?.journals?.thumbnail_url || null) : null;
205→
206→                return(
207→                    <div key={`${unreadNotification.source}-${unreadNotification.id}`} className={unreadNotification?.read ? "notification-cards" : "notification-cards-unread"}>
208→
209→                        <div className="notification-cards-child-container">
210→
211→                            <div className="notification-icon-container">
212→                                {iconArray.map((icon, index) => (
213→                                    <div className="notification-icon" key={index}>
214→                                        {icon.type === displayType ? icon.icon : null}
215→                                    </div>
216→                                ))}
217→                            </div>
218→
219→                            <div className="notification-contents-container">
220→
221→                                <div className="notification-sender-user-metadata">
222→                                    <div className="notification-sender-user-metadata-child">
223→                                        <div className={`notif-sender-profilepic-container ${unreadNotification?.users?.badge === 'legend' ? 'notif-avatar-ring-legend' : unreadNotification?.users?.badge === 'og' ? 'notif-avatar-ring-og' : ''}`}>
224→                                            <img className="notif-sender-profilepic" loading="lazy" src={unreadNotification?.users?.image_url || '/assets/profile.jpg'} alt="notificataion sender profile picture" />
225→                                        </div>
226→
227→                                        <div className="notif-sender-name-container">
228→                                            <p className="notif-sender-name">{unreadNotification?.users?.name}</p>
229→                                            <VerifiedBadge badge={unreadNotification?.users?.badge} size={14} />
230→                                            <p className="notif-type">{FormatNotificationType(displayType)}</p>
231→                                        </div>
232→
233→                                        <div className="notification-date-container">
234→                                            <p className="notification-date">{formatPostDate(unreadNotification?.created_at)}</p>
235→                                        </div>
236→
237→                                    </div>
238→
239→                                    <div ref={modalRef} className="notification-settings">
240→                                        {settingsId === unreadNotification?.id && (
241→                                            <AnimatePresence>
242→                                            <motion.div
243→                                            initial={{opacity: 0, scale: 0}}
244→                                            animate={{opacity: 1, scale: 1, transition: {type: 'spring', stiffness: 300, damping: 25, mass: 0.8}}}
245→                                            exit={{opacity: 0, scale: 0, transition: {duration: 0.2, ease: 'easeInOut'}}}
246→                                            className="settings-container"
247→                                            >
248→                                                <div onClick={(e) => handleClickDeleteNotification(e, unreadNotification?.id, unreadNotification?.source)} className="delete-notification">
249→                                                    <svg xmlns="http://www.w3.org/2000/svg" width="20px" height="20px" viewBox="0 0 24 24" fill="none">
250→                                                        <path d="M10 12V17" stroke="#000000" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"/>
251→                                                        <path d="M14 12V17" stroke="#000000" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"/>
252→                                                        <path d="M4 7H20" stroke="#000000" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"/>
253→                                                        <path d="M6 10V18C6 19.6569 7.34315 21 9 21H15C16.6569 21 18 19.6569 18 18V10" stroke="#000000" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"/>
254→                                                        <path d="M9 5C9 3.89543 9.89543 3 11 3H13C14.1046 3 15 3.89543 15 5V7H9V5Z" stroke="#000000" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"/>
255→                                                    </svg>
256→                                                    Delete this notification
257→                                                </div>
258→                                            </motion.div>
259→                                            </AnimatePresence>
260→                                        )}
261→
262→                                        <svg onClick={(e) => handleClickSettings(e, unreadNotification?.id)} xmlns="http://www.w3.org/2000/svg" width="20px" height="20px" viewBox="0 0 24 24" fill="none">
263→                                            <g id="style=fill">
264→                                                <g id="menu-meatballs">
265→                                                    <path id="vector (Stroke)" fillRule="evenodd" clipRule="evenodd" d="M2.75 12C2.75 10.7574 3.75736 9.75 5 9.75C6.24264 9.75 7.25 10.7574 7.25 12C7.25 13.2426 6.24264 14.25 5 14.25C3.75736 14.25 2.75 13.2426 2.75 12Z" fill="#000000"/>
266→                                                    <path id="vector (Stroke)_2" fillRule="evenodd" clipRule="evenodd" d="M9.75 12C9.75 10.7574 10.7574 9.75 12 9.75C13.2426 9.75 14.25 10.7574 14.25 12C14.25 13.2426 13.2426 14.25 12 14.25C10.7574 14.25 9.75 13.2426 9.75 12Z" fill="#000000"/>
267→                                                    <path id="vector (Stroke)_3" fillRule="evenodd" clipRule="evenodd" d="M16.75 12C16.75 10.7574 17.7574 9.75 19 9.75C20.2426 9.75 21.25 10.7574 21.25 12C21.25 13.2426 20.2426 14.25 19 14.25C17.7574 14.25 16.75 13.2426 16.75 12Z" fill="#000000"/>
268→                                                </g>
269→                                            </g>
270→                                        </svg>
271→                                    </div>
272→
273→                                </div>
274→
275→                                <div className="notification-content"
276→                                    onClick={(e) => handleReadNotif(e, unreadNotification)}
277→                                >
278→                                    {isOpinion ? (
279→                                        <div className="notification-content-text">
280→                                            <p className="notif-content-sliced-text">{unreadNotification?.opinions?.opinion?.length > 100 ? unreadNotification?.opinions?.opinion?.substring(0, 100) + '...' : unreadNotification?.opinions?.opinion}</p>
281→                                        </div>
282→                                    ) : (
283→                                        <>
284→                                        <div className="notification-content-text">
285→                                            <p className="notif-content-title">{unreadNotification?.journals?.title?.length > 40 ? unreadNotification?.journals?.title?.substring(0, 39) : unreadNotification?.journals?.title}</p>
286→                                            <p className="notif-content-sliced-text">{previewText}</p>
287→                                        </div>
288→                                        <div className="notif-content-image-container">
289→                                            <img className="notif-content-image" loading="lazy" src={thumbnailUrl || '/assets/no-image.png'} alt={unreadNotification?.journals?.title ? `${unreadNotification.journals.title} cover image` : "Notification post cover image"} onError={handleImageFallback} />
290→                                        </div>
291→                                        </>
292→                                    )}
293→                                </div>
294→                            </div>
295→                        </div>
296→
297→                    </div>
298→                )
299→            })}
300→            <div ref={inviewRef} className="notification-inview-container">
301→                {isFetchinNextPage && (
302→                    <MoonLoader loading={isFetchinNextPage} color="var(--loader-color)" size={20}/>
303→                )}
304→            </div>
305→        </div>
306→        </>
307→    )
308→}
309→
310→export default UnreadNotification;
