 98→const NotificationCards = () =>{
 99→    const {user, session} = useAuth();
100→    const {ref, inView} = useInView({
101→        threshold: 0.2
102→    })
103→    const navigate = useNavigate();
104→
105→    const scrollToTop = useRef();
106→    const modalRef = useRef();
107→    const [settingsId, setSettingsId] = useState(null);
108→
109→    const iconArray = NOTIFICATION_ICON_ARRAY;
110→
111→    const handleClickNotif = handleCLickContent(navigate);
112→    const handleClickOpinionNotif = handleClickOpinion(navigate);
113→    const mutationReadNotif = useReadNotificationMutation(session);
114→
115→    const handleReadNotif = async(e, notification) => {
116→        e.stopPropagation();
117→        const source = notification?.source || 'journal';
118→        mutationReadNotif.mutate({notifId: notification.id, source})
119→
120→        if(source === 'opinion'){
121→            handleClickOpinionNotif(e, notification?.opinions?.id, notification?.opinions?.user_id)
122→        } else if(notification?.type === 'follow'){
123→            navigate(`/visitProfile?userId=${notification?.sender_id}`);
124→        } else if(notification?.type === 'repost' && notification?.repost_journal_id){
125→            // Navigate to the repost post (quote + embedded original)
126→            const repostId = notification.repost_journal_id;
127→            const encodedId = encodeURIComponent(repostId);
128→            navigate(`/home/post/${encodedId}`);
129→        } else {
130→            handleClickNotif(
131→                e,
132→                null,
133→                '',
134→                notification?.journals?.title,
135→                notification?.journals?.users.id,
136→                notification?.journals?.users?.name,
137→                notification?.journals?.users?.image_url,
138→                notification?.journals?.created_at,
139→                notification?.journal_id,
140→                notification?.hasLiked,
141→                0,
142→                notification?.hasBookMarked,
143→                0,
144→                0,
145→                notification?.journals?.users?.badge,
146→            )
147→        }
148→    }
149→
150→    const {data, isLoading, hasNextPage, isFetchingNextPage, fetchNextPage} = useInfiniteQuery({
151→        queryKey: ['getNotifications', session?.user?.id],
152→        queryFn: ({pageParam = null}) => getNotifications(session?.access_token, pageParam, 5),
153→        getNextPageParam: (lastpage) =>{
154→            if(lastpage?.hasMore){
155→                const lastNotification = lastpage?.data[lastpage?.data.length - 1];
156→                return new Date(lastNotification.created_at).toISOString();
157→
158→            }
159→            return undefined;
160→        },
161→        enabled: !!session?.access_token,
162→        refetchOnWindowFocus: false,
163→        staleTime: 1000 * 60 * 2
164→    })
165→
166→    useEffect(() =>{
167→        if(scrollToTop.current && !isLoading){
168→            scrollToTop.current.scrollIntoView({behavior: 'smooth'});
169→        }
170→    }, [isLoading])
171→
172→    useEffect(() =>{
173→        if(hasNextPage && !isFetchingNextPage && inView){
174→            // console.log(hasNextPage)
175→            fetchNextPage();
176→        }
177→    }, [hasNextPage, isFetchingNextPage, inView, fetchNextPage])
178→
179→    const notifications = useMemo(() => data?.pages?.flatMap((page) => page?.data) || [], [data]);
180→
181→    useEffect(() =>{
182→        const handleClickOutside = (e) =>{
183→            if(modalRef.current && !modalRef.current.contains(e.target)){
184→                setSettingsId(null);
185→                // console.log('close')
186→            }
187→        }
188→
189→        document.addEventListener('click', handleClickOutside);
190→        return () =>{
191→            document.removeEventListener('click', handleClickOutside)
192→        }
193→    }, [])
194→
195→     useEffect(() =>{
196→         // console.log(data)
197→    }, [data])
198→
199→    const handleClickSettings = (e, notifId) =>{
200→        e.stopPropagation();
201→        // console.log(notifId)
202→        setSettingsId(settingsId === notifId ? null : notifId);
203→    }
204→
205→    const mutationDeleteNotif  = useUserDeleteNotificationMutation(session);
206→
207→    const handleClickDeleteNotification = async(e, notifId, source) =>{
208→        e.stopPropagation();
209→        try {
210→           const message = mutationDeleteNotif.mutateAsync({notifId, source});
211→            if(message){
212→                // console.log(message)
213→            }
214→        } catch (error) {
215→            console.error('error while deleting notification:', error)
216→        }
217→    }
218→
219→    if(notifications.length === 0 && !isLoading){
220→        return(
221→            <div className='notification-loading-container'>
222→                No notifications availabe
223→            </div>
224→        )
225→    }
226→
227→    if(isLoading){
228→        return(
229→            <div className="notification-loading-container">
230→                <MoonLoader size={25} color="var(--loader-color)" loading={isLoading}/>
231→            </div>
232→        )
233→    }
234→
235→    return(
236→        <>
237→        <div ref={scrollToTop}/>
238→        <div className="notifications-container">
239→            {notifications?.map((notification) => {
240→                const isOpinion = notification?.source === 'opinion';
241→                const displayType = isOpinion
242→                    ? (notification?.type === 'mention' ? 'mention' : 'opinion_reply')
243→                    : notification?.type;
244→                const previewText = !isOpinion ? (notification?.journals?.preview_text || '') : '';
245→                const thumbnailUrl = !isOpinion ? (notification?.journals?.thumbnail_url || null) : null;
246→
247→                return(
248→                <div key={`${notification.source}-${notification.id}`} className={notification?.read ? "notification-cards" : "notification-cards-unread"}>
249→
250→                    <div className="notification-cards-child-container">
251→
252→                        <div className="notification-icon-container">
253→                            {displayType === 'reaction' ? (
254→                                <div className="notification-icon">
255→                                    <span style={{ fontSize: '26px', lineHeight: 1 }}>{getReactionEmoji(notification?.reaction_type) || '❤️'}</span>
256→                                </div>
257→                            ) : (
258→                                iconArray.map((icon, index) => (
259→                                    <div className="notification-icon" key={index}>
260→                                        {icon.type === displayType ? icon.icon : null}
261→                                    </div>
262→                                ))
263→                            )}
264→                        </div>
265→
266→                        <div className="notification-contents-container">
267→
268→                            <div className="notification-sender-user-metadata">
269→                                <div className="notification-sender-user-metadata-child">
270→                                    <div className={`notif-sender-profilepic-container ${notification?.users?.badge === 'legend' ? 'notif-avatar-ring-legend' : notification?.users?.badge === 'og' ? 'notif-avatar-ring-og' : ''}`}>
271→                                        <img loading="lazy" className="notif-sender-profilepic" src={notification?.users?.image_url || '/assets/profile.jpg'} alt="notificataion sender profile picture" />
272→                                    </div>
273→
274→                                    <div className="notif-sender-name-container">
275→                                        <p className="notif-sender-name">{notification?.users?.name}</p>
276→                                        <VerifiedBadge badge={notification?.users?.badge} size={14} />
277→                                        <p className="notif-type">{FormatNotificationType(displayType, notification?.reaction_type)}</p>
278→                                    </div>
279→
280→                                    <div className="notification-date-container">
281→                                        <p className="notification-date">{formatPostDate(notification?.created_at)}</p>
282→                                    </div>
283→                                </div>
284→                                <div className="notification-settings">
285→                                    {settingsId === notification.id && (
286→                                        <AnimatePresence>
287→                                        <motion.div
288→                                        initial={{opacity: 0, scale: 0}}
289→                                        animate={{opacity: 1, scale: 1, transition:{type: 'spring', stiffness: 300, damping: 25, mass: 0.8}}}
290→                                        exit={{ opacity: 0, scale: 0,
291→                                            transition: {
292→                                            duration: 0.2,
293→                                            ease: "easeOut"
294→                                            }
295→                                        }}
296→                                        ref={modalRef}
297→                                        className="settings-container">
298→
299→                                            <div onClick={(e) => handleClickDeleteNotification(e, notification?.id, notification?.source)} className="delete-notification">
300→                                                <svg xmlns="http://www.w3.org/2000/svg" width="20px" height="20px" viewBox="0 0 24 24" fill="none">
301→                                                    <path d="M10 12V17" stroke="#000000" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"/>
302→                                                    <path d="M14 12V17" stroke="#000000" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"/>
303→                                                    <path d="M4 7H20" stroke="#000000" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"/>
304→                                                    <path d="M6 10V18C6 19.6569 7.34315 21 9 21H15C16.6569 21 18 19.6569 18 18V10" stroke="#000000" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"/>
305→                                                    <path d="M9 5C9 3.89543 9.89543 3 11 3H13C14.1046 3 15 3.89543 15 5V7H9V5Z" stroke="#000000" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"/>
306→                                                </svg>
307→                                                Delete this notification
308→                                            </div>
309→
310→                                        </motion.div>
311→                                        </AnimatePresence>
312→                                    )}
313→
314→                                    <svg onClick={(e) => handleClickSettings(e, notification?.id)} xmlns="http://www.w3.org/2000/svg" width="20px" height="20px" viewBox="0 0 24 24" fill="none">
315→                                        <g id="style=fill">
316→                                            <g id="menu-meatballs">
317→                                                <path id="vector (Stroke)" fillRule="evenodd" clipRule="evenodd" d="M2.75 12C2.75 10.7574 3.75736 9.75 5 9.75C6.24264 9.75 7.25 10.7574 7.25 12C7.25 13.2426 6.24264 14.25 5 14.25C3.75736 14.25 2.75 13.2426 2.75 12Z" fill="#000000"/>
318→                                                <path id="vector (Stroke)_2" fillRule="evenodd" clipRule="evenodd" d="M9.75 12C9.75 10.7574 10.7574 9.75 12 9.75C13.2426 9.75 14.25 10.7574 14.25 12C14.25 13.2426 13.2426 14.25 12 14.25C10.7574 14.25 9.75 13.2426 9.75 12Z" fill="#000000"/>
319→                                                <path id="vector (Stroke)_3" fillRule="evenodd" clipRule="evenodd" d="M16.75 12C16.75 10.7574 17.7574 9.75 19 9.75C20.2426 9.75 21.25 10.7574 21.25 12C21.25 13.2426 20.2426 14.25 19 14.25C17.7574 14.25 16.75 13.2426 16.75 12Z" fill="#000000"/>
320→                                            </g>
321→                                        </g>
322→                                    </svg>
323→                                </div>
324→
325→                            </div>
326→
327→                            <div
328→                            className="notification-content"
329→                            onClick={(e) => handleReadNotif(e, notification)}
330→                            >
331→                                {displayType === 'follow' ? (
332→                                    <div className="notification-content-text">
333→                                        <p className="notif-content-sliced-text">started following you</p>
334→                                    </div>
335→                                ) : isOpinion ? (
336→                                    <div className="notification-content-text">
337→                                        <p className="notif-content-sliced-text">{notification?.opinions?.opinion?.length > 100 ? notification?.opinions?.opinion?.substring(0, 100) + '...' : notification?.opinions?.opinion}</p>
338→                                    </div>
339→                                ) : (
340→                                    <>
341→                                    <div className="notification-content-text">
342→                                        <p className="notif-content-title">{notification?.journals?.title?.length > 40 ? notification?.journals?.title?.substring(0, 39) : notification?.journals?.title}</p>
343→                                        <p className="notif-content-sliced-text">{previewText}</p>
344→                                    </div>
345→                                    <div className="notif-content-image-container">
346→                                        <img loading="lazy" className="notif-content-image" src={thumbnailUrl || '/assets/no-image.png'} alt={notification?.journals?.title ? `${notification.journals.title} cover image` : "Notification post cover image"} onError={handleImageFallback} />
347→                                    </div>
348→                                    </>
349→                                )}
350→                            </div>
351→                        </div>
352→
353→                    </div>
354→
355→                </div>
356→                )
357→            })}
358→            <div className="notification-inview-container" ref={ref}>
359→                {isFetchingNextPage && (
360→                    <MoonLoader size={20} color="var(--loader-color)"/>
361→                )}
362→                
363→            </div>
364→        </div>
365→        </>
366→    )
367→}
