1006→    startedAt: metricsState.startedAt,
1007→    now: new Date().toISOString(),
1008→});
1009→
1010→const isMetricsAuthorized = (req) => {
1011→    if (!METRICS_TOKEN) {
1012→        return true;
1013→    }
1014→
1015→    const providedToken = String(req.headers['x-metrics-token'] || '').trim();
1016→    return Boolean(providedToken && providedToken === METRICS_TOKEN);
1017→};
1018→
1019→const buildMetricsPayload = () => {
1020→    const routeStats = Array.from(metricsState.routeStats.entries())
1021→        .map(([route, stat]) => ({
1022→            route,
1023→            count: stat.count,
1024→            avgDurationMs: stat.count > 0 ? Number((stat.totalDurationMs / stat.count).toFixed(2)) : 0,
1025→            maxDurationMs: Number(stat.maxDurationMs.toFixed(2)),
1026→            bytesSent: stat.bytesSent,
1027→            statusBuckets: stat.statusBuckets,
1028→        }))
1029→        .sort((a, b) => b.count - a.count);
1030→
1031→    return {
1032→        startedAt: metricsState.startedAt,
1033→        requests: metricsState.requests,
1034→        responses: metricsState.responses,
1035→        inFlight: metricsState.inFlight,
1036→        bytesSent: metricsState.bytesSent,
1037→        statusBuckets: metricsState.statusBuckets,
1038→        routeStats: routeStats,
1039→    };
1040→};
