252→                        <div className="notification-icon-container">
253→                            {displayType === 'reaction' ? (
254→                                <div className="notification-icon">
255→                                    <span style={{ fontSize: '26px', lineHeight: 1 }}>{getReactionEmoji(notification?.reaction_type) || '❤️'}</span>
256→                                </div>
257→                            ) : (
258→                                iconArray.map((icon, index) => (
259→                                    <div className="notification-icon" key={index}>
260→                                        {icon.type === displayType ? icon.icon : null}
261→                                    </div>
262→                                ))
263→                            )}
264→                        </div>
265→
266→                        <div className="notification-contents-container">
267→
268→                            <div className="notification-sender-user-metadata">
269→                                <div className="notification-sender-user-metadata-child">
270→                                    <div className={`notif-sender-profilepic-container ${notification?.users?.badge === 'legend' ? 'notif-avatar-ring-legend' : notification?.users?.badge === 'og' ? 'notif-avatar-ring-og' : ''}`}>
271→                                        <img loading="lazy" className="notif-sender-profilepic" src={notification?.users?.image_url || '/assets/profile.jpg'} alt="notificataion sender profile picture" />
272→                                    </div>
273→
274→                                    <div className="notif-sender-name-container">
275→                                        <p className="notif-sender-name">{notification?.users?.name}</p>
276→                                        <VerifiedBadge badge={notification?.users?.badge} size={14} />
277→                                        <p className="notif-type">{FormatNotificationType(displayType, notification?.reaction_type)}</p>
278→                                    </div>
279→
280→                                    <div className="notification-date-container">
281→                                        <p className="notification-date">{formatPostDate(notification?.created_at)}</p>
282→                                    </div>
283→                                </div>
284→                                <div className="notification-settings">
285→                                    {settingsId === notification.id && (
286→                                        <AnimatePresence>
