 16→const incrementReplyCount = (old, parentId) => {
 17→    if (!old || !Array.isArray(old.pages)) return old;
 18→
 19→    return {
 20→        ...old,
 21→        pages: old.pages.map((page) => ({
 22→            ...page,
 23→            comments: Array.isArray(page?.comments)
 24→                ? page.comments.map((comment) => {
 25→                    if (comment?.id !== parentId) return comment;
 26→                    return {
 27→                        ...comment,
 28→                        reply_count: (comment?.reply_count || 0) + 1,
 29→                    };
 30→                })
 31→                : page?.comments,
 32→        })),
 33→    };
 34→};
