 37→const CommentsCards = ({comments, postId}) =>{
 38→    const {user, session} = useAuth();
 39→    const userId = user?.userData[0].id;
 40→    const queryClient = useQueryClient();
 41→
 42→    const [showReplyInput, setShowReplyInput] = useState(false);
 43→    const [showReplies, setShowReplies] = useState(false);
