 52→
 53→    const clickProfile = handleClickProfile(navigate);
 54→
 55→    const {data, isLoading, fetchNextPage, hasNextPage, isFetchinNextPage} = useInfiniteQuery({
 56→        queryKey: ['getPostReplies', comments.id],
 57→        queryFn: ({pageParam = null, queryKey}) => getPostReplies(queryKey[1], 5, pageParam),
 58→        getNextPageParam: (lastPage) => {
 59→            if(lastPage.hasMore){
 60→                const lastReply = lastPage?.data[lastPage?.data.length - 1];
 61→                return lastReply.id;
 62→            } else{
 63→                return undefined
 64→            }
 65→        },
 66→        refetchOnWindowFocus: false,
 67→        enabled: showReplies,
 68→        staleTime: 1000 * 60 * 5
 69→    })
 70→
 71→    const handleClickReplyButton = (e) =>{
 72→        e.stopPropagation();
 73→        setShowReplyInput(!showReplyInput);
 74→    }
 75→
 76→    const handleShowMoreReplies = () => {
 77→        if(!isFetchinNextPage){
 78→            fetchNextPage();
 79→        }
 80→    }
 81→
 82→    const submitReply = async(parent_id, receiver_id) => {
 83→        const trimmedReply = reply.trim();
 84→        if (!trimmedReply) return;
 85→
 86→        setReplyLoaderId(parent_id)
 87→        queryClient.cancelQueries({ queryKey: ['getPostReplies', parent_id] });
 88→        queryClient.cancelQueries({ queryKey: ['postComments', postId] });
 89→
 90→        const previousReplies = queryClient.getQueryData(['getPostReplies', parent_id]);
 91→        const previousComments = queryClient.getQueryData(['postComments', postId]);
 92→
 93→        const optimisticReply = {
 94→            id: `optimistic-reply-${Date.now()}`,
 95→            post_id: postId,
 96→            parent_id: parent_id,
 97→            comment: trimmedReply,
 98→            created_at: new Date().toISOString(),
 99→            user_id: user?.userData?.[0]?.id,
100→            users: {
101→                id: user?.userData?.[0]?.id,
