104→                badge: user?.userData?.[0]?.badge,
105→            },
106→            reply_count: 0,
107→        };
108→
109→        queryClient.setQueryData(['getPostReplies', parent_id], (old) => {
110→            if (!old || !Array.isArray(old.pages)) {
111→                return {
112→                    pageParams: [null],
113→                    pages: [{ data: [optimisticReply], hasMore: false }],
114→                };
115→            }
116→
117→            return {
118→                ...old,
119→                pages: old.pages.map((page, index) =>
120→                    index === 0
121→                        ? { ...page, data: [optimisticReply, ...(page?.data || [])] }
122→                        : page
123→                ),
124→            };
125→        });
126→        queryClient.setQueryData(['postComments', postId], (old) => incrementReplyCount(old, parent_id));
127→
128→        try {
129→            const formdata = new FormData();
130→            formdata.append('reply', trimmedReply);
131→
132→            const message = await addReply(userId, postId, parent_id, formdata, receiver_id, session?.access_token);
133→            if(message){
134→                // console.log(message);
135→            }
136→            queryClient.invalidateQueries({ queryKey: ['getPostReplies', parent_id] });
137→            queryClient.invalidateQueries({ queryKey: ['postComments', postId] });
138→            setReply('')
139→            setShowReplies(true)
140→        } catch (error) {
141→            queryClient.setQueryData(['getPostReplies', parent_id], previousReplies);
142→            queryClient.setQueryData(['postComments', postId], previousComments);
143→            setReply('')
144→            throw new Error('error adding replies')
145→        } finally {
146→            setReplyLoaderId('')
147→            setShowReplyInput(false);
148→        }
149→    }
150→
151→    useEffect(() =>{
152→        if(showReplyInput && replyInputRef.current){
153→            const timer = setTimeout(() => {
154→                replyInputRef.current.focus();
155→                replyInputRef.current.scrollIntoView({behavior: 'smooth', block: 'center'})
156→            }, 50);
157→
158→            return () => {
159→                clearTimeout(timer)
160→            }
161→        }
162→    }, [showReplyInput])
163→
164→    const replies = data?.pages.flatMap((page) => page.data) || [];
165→
166→    return(
167→        <div className={`cm-card ${comments?.parent_id ? 'cm-card--reply' : ''}`}>
