181→                    >
182→                        {comments?.users?.name}
183→                    </span>
184→                    <VerifiedBadge badge={comments?.users?.badge} size={14} />
185→                    <span className="cm-dot">&middot;</span>
186→                    <span className="cm-date">{formatPostDate(comments?.created_at)}</span>
187→                </div>
188→
189→                <p className="cm-body"><MentionText text={comments?.comment} /></p>
190→
191→                <div className="cm-card-actions">
192→                    <button onClick={(e) => handleClickReplyButton(e)} className="cm-reply-btn">
193→                        <svg width="12" height="12" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
194→                            <polyline points="9 17 4 12 9 7" />
195→                            <path d="M20 18v-2a4 4 0 0 0-4-4H4" />
196→                        </svg>
197→                        Reply
198→                    </button>
199→
200→                    {comments?.reply_count > 0 && (
201→                        <button onClick={() => setShowReplies(!showReplies)} className="cm-toggle-replies-btn">
202→                            <motion.svg
203→                                width="12" height="12" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round"
204→                                animate={{ rotate: showReplies ? 180 : 0 }}
205→                                transition={{ duration: 0.2 }}
206→                            >
207→                                <polyline points="6 9 12 15 18 9" />
208→                            </motion.svg>
209→                            <span className="cm-replies-count-badge">{comments?.reply_count}</span>
210→                            {showReplies ? 'Hide replies' : 'View replies'}
211→                        </button>
212→                    )}
213→                </div>
214→
215→                {replyLoaderId === comments.id && (
216→                    <div className="cm-reply-loading">
217→                        <MoonLoader size={16} color="var(--loader-color)" speedMultiplier={0.8}/>
218→                    </div>
219→                )}
220→
221→                <AnimatePresence>
222→                    {showReplyInput && (
223→                        <motion.div
224→                            initial={{ height: 0, opacity: 0 }}
225→                            animate={{ height: "auto", opacity: 1 }}
226→                            exit={{ height: 0, opacity: 0 }}
227→                            transition={{ duration: 0.2 }}
228→                            className="cm-reply-input-wrapper"
229→                        >
230→                            <ReplyContextChip name={comments?.users?.name} onDismiss={(e) => handleClickReplyButton(e)} />
231→                            <textarea
232→                                ref={replyInputRef}
233→                                maxLength={200}
234→                                value={reply}
235→                                onChange={(e) => { setReply(e.target.value); mentionTextareaProps.onChange(e); }}
236→                                onKeyDown={mentionTextareaProps.onKeyDown}
237→                                onKeyUp={mentionTextareaProps.onKeyUp}
238→                                className="cm-reply-textarea"
239→                                placeholder={`Replying to ${comments?.users?.name}...`}
