115→            ...queryClient.getQueriesData({ queryKey: ['userJournals'] }),
116→            ...queryClient.getQueriesData({ queryKey: ['visitedProfileJournals'] }),
117→        ];
118→
119→        queryClient.setQueryData(['postComments', postId], (old) => {
120→            if (!old || !Array.isArray(old.pages)) {
121→                return {
122→                    pageParams: [null],
123→                    pages: [{ comments: [optimisticComment], hasMore: false }],
124→                };
125→            }
126→
127→            return {
128→                ...old,
129→                pages: old.pages.map((page, index) =>
130→                    index === 0
131→                        ? { ...page, comments: [optimisticComment, ...(page?.comments || [])] }
132→                        : page
133→                ),
134→            };
135→        });
136→
137→        queryClient.setQueriesData({ queryKey: ['journals'] }, (old) => incrementJournalCommentCount(old, postId));
138→        queryClient.setQueriesData({ queryKey: ['userJournals'] }, (old) => incrementJournalCommentCount(old, postId));
139→        queryClient.setQueriesData({ queryKey: ['visitedProfileJournals'] }, (old) => incrementJournalCommentCount(old, postId));
