const NOTIFICATION_ICONS = {
    like: <svg .../>,
    reply: <svg .../>,
    opinion_reply: <svg .../>,   // same component, no duplication
    // ...
};
// Usage:
<div className="notification-icon">{NOTIFICATION_ICONS[displayType] ?? null}</div>
```

