/**
 * Returns the CSS class for a badge ring given a badge type and prefix.
 * @param {string|undefined} badge - 'legend', 'og', or undefined
 * @param {string} prefix - CSS class prefix (e.g. 'avatar-ring', 'cm-ring', 'notif-avatar-ring')
 * @returns {string} CSS class or empty string
 */
export const getBadgeRingClass = (badge, prefix = 'avatar-ring') => {
    if (badge === 'legend') return `${prefix}-legend`;
    if (badge === 'og') return `${prefix}-og`;
    return '';
};

