 80→const UnreadNotification = () =>{
 81→    const {ref: inviewRef, inView} = useInView({threshold: 0.2});
 82→
 83→    const {session, user} = useAuth();
 84→    const modalRef = useRef();
 85→    const navigate = useNavigate();
 86→
 87→    const [settingsId, setSettingsId] = useState(null);
 88→
 89→    const handleClickSettings = (e, notifId) =>{
 90→        e.stopPropagation();
 91→        setSettingsId(settingsId === notifId ? null : notifId);
 92→    }
 93→
 94→    const deleteNotifMutation = useUserDeleteNotificationMutation(session);
 95→    const handleClickDeleteNotification = (e, notifId, source) =>{
 96→        e.stopPropagation();
 97→        try {
 98→            const message = deleteNotifMutation.mutateAsync({notifId, source});
 99→            if(message){
100→                // console.log(message)
101→            }
102→        } catch (error) {
103→            console.error('error deleting notification',error)
104→        }
105→    }
106→
107→
108→    const {data, isLoading, isFetchingNextPage, hasNextPage, fetchNextPage} = useInfiniteQuery({
109→        queryKey: ['unreadNotification', session?.user?.id],
110→        queryFn: ({pageParam = null}) => getUnreadNotification(session?.access_token, pageParam, 5),
111→        getNextPageParam: (lastPage) => {
112→            if(lastPage.hasMore){
113→                const lastJournal = lastPage?.data[lastPage?.data?.length - 1];
114→                return new Date(lastJournal.created_at).toISOString();
115→            } else {
116→                return undefined;
117→            }
118→        },
119→        enabled: !!session,
120→        refetchOnWindowFocus: false,
121→        staleTime: 1000 * 60 * 2
122→    })
123→
124→    useEffect(() => {
125→        if(inView && !isFetchingNextPage && hasNextPage){
126→            fetchNextPage();
127→        }
128→    }, [fetchNextPage, hasNextPage, isFetchingNextPage, inView])
129→
130→    const handleClickNotif = handleCLickContent(navigate);
131→    const handleClickOpinionNotif = handleClickOpinion(navigate);
132→    const mutationReadNotif = useReadNotificationMutation(session);
133→
134→    const handleReadNotif = async(e, notification) =>{
135→        const source = notification?.source || 'journal';
136→        mutationReadNotif.mutate({notifId: notification.id, source});
137→
138→        if(source === 'opinion'){
139→            handleClickOpinionNotif(e, notification?.opinions?.id, notification?.opinions?.user_id)
140→        } else {
141→            handleClickNotif(
142→                e,
143→                null,
144→                '',
145→                notification?.journals?.title,
146→                notification?.journals?.users?.id,
147→                notification?.journals?.users?.name,
148→                notification?.journals?.users?.image_url,
149→                notification?.journals?.created_at,
150→                notification?.journal_id,
151→                notification?.hasLiked,
152→                0,
153→                notification?.hasBookMarked,
154→                0,
155→                0
156→            )
157→        }
158→    }
159→
160→    const unreadNotifications = data?.pages?.flatMap((page) => page.data) || [];
161→    
162→    // useEffect(() =>{
163→    //     console.log(unreadNotifications)
164→    // }, [data])
165→
166→    useEffect(() => {
167→        const handleClickOutside = (e) =>{
168→            if(modalRef.current && !modalRef.current.contains(e.target)){
169→                setSettingsId(null);
170→            }
171→        }
172→        document.addEventListener('mousedown', handleClickOutside);
173→
174→        return() => {
175→            document.removeEventListener('mousedown', handleClickOutside)
176→        }
177→    }, [])
178→
179→    if(unreadNotifications.length === 0 && !isLoading){
180→        return(
181→            <div className='notification-loading-container'>
182→                No unread notifications available
183→            </div>
184→        )
185→    }
186→    if(isLoading) {
187→        return(
188→            <div className="notification-loading-container">
189→                <MoonLoader size={25} color="var(--loader-color)" loading={isLoading}/>
190→            </div>
191→        )
192→    }
193→
194→    return(
195→        <>
196→        <div className="unread-notification-component-container">
197→            {unreadNotifications?.map((unreadNotification) => {
198→                const isOpinion = unreadNotification?.source === 'opinion';
199→                const displayType = isOpinion
200→                    ? (unreadNotification?.type === 'mention' ? 'mention' : 'opinion_reply')
201→                    : unreadNotification?.type;
202→                const previewText = !isOpinion ? (unreadNotification?.journals?.preview_text || '') : '';
203→                const thumbnailUrl = !isOpinion ? (unreadNotification?.journals?.thumbnail_url || null) : null;
204→
205→                return(
206→                    <div key={`${unreadNotification.source}-${unreadNotification.id}`} className={unreadNotification?.read ? "notification-cards" : "notification-cards-unread"}>
207→
208→                        <div className="notification-cards-child-container">
209→
210→                            <div className="notification-icon-container">
211→                                {UNREAD_ICON_ARRAY.map((icon, index) => (
212→                                    <div className="notification-icon" key={index}>
213→                                        {icon.type === displayType ? icon.icon : null}
214→                                    </div>
215→                                ))}
216→                            </div>
217→
218→                            <div className="notification-contents-container">
219→
220→                                <div className="notification-sender-user-metadata">
221→                                    <div className="notification-sender-user-metadata-child">
222→                                        <div className={`notif-sender-profilepic-container ${unreadNotification?.users?.badge === 'legend' ? 'notif-avatar-ring-legend' : unreadNotification?.users?.badge === 'og' ? 'notif-avatar-ring-og' : ''}`}>
223→                                            <img className="notif-sender-profilepic" loading="lazy" src={unreadNotification?.users?.image_url || '/assets/profile.jpg'} alt="notificataion sender profile picture" />
224→                                        </div>
225→
226→                                        <div className="notif-sender-name-container">
227→                                            <p className="notif-sender-name">{unreadNotification?.users?.name}</p>
228→                                            <VerifiedBadge badge={unreadNotification?.users?.badge} size={14} />
229→                                            <p className="notif-type">{FormatNotificationType(displayType)}</p>
230→                                        </div>
231→
232→                                        <div className="notification-date-container">
233→                                            <p className="notification-date">{formatPostDate(unreadNotification?.created_at)}</p>
234→                                        </div>
235→
236→                                    </div>
237→
238→                                    <div ref={modalRef} className="notification-settings">
239→                                        {settingsId === unreadNotification?.id && (
240→                                            <AnimatePresence>
241→                                            <motion.div
242→                                            initial={{opacity: 0, scale: 0}}
243→                                            animate={{opacity: 1, scale: 1, transition: {type: 'spring', stiffness: 300, damping: 25, mass: 0.8}}}
244→                                            exit={{opacity: 0, scale: 0, transition: {duration: 0.2, ease: 'easeInOut'}}}
245→                                            className="settings-container"
246→                                            >
247→                                                <div onClick={(e) => handleClickDeleteNotification(e, unreadNotification?.id, unreadNotification?.source)} className="delete-notification">
248→                                                    <svg xmlns="http://www.w3.org/2000/svg" width="20px" height="20px" viewBox="0 0 24 24" fill="none">
249→                                                        <path d="M10 12V17" stroke="#000000" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"/>
250→                                                        <path d="M14 12V17" stroke="#000000" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"/>
251→                                                        <path d="M4 7H20" stroke="#000000" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"/>
252→                                                        <path d="M6 10V18C6 19.6569 7.34315 21 9 21H15C16.6569 21 18 19.6569 18 18V10" stroke="#000000" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"/>
253→                                                        <path d="M9 5C9 3.89543 9.89543 3 11 3H13C14.1046 3 15 3.89543 15 5V7H9V5Z" stroke="#000000" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"/>
254→                                                    </svg>
255→                                                    Delete this notification
256→                                                </div>
257→                                            </motion.div>
258→                                            </AnimatePresence>
259→                                        )}
260→
261→                                        <svg onClick={(e) => handleClickSettings(e, unreadNotification?.id)} xmlns="http://www.w3.org/2000/svg" width="20px" height="20px" viewBox="0 0 24 24" fill="none">
262→                                            <g id="style=fill">
263→                                                <g id="menu-meatballs">
264→                                                    <path id="vector (Stroke)" fillRule="evenodd" clipRule="evenodd" d="M2.75 12C2.75 10.7574 3.75736 9.75 5 9.75C6.24264 9.75 7.25 10.7574 7.25 12C7.25 13.2426 6.24264 14.25 5 14.25C3.75736 14.25 2.75 13.2426 2.75 12Z" fill="#000000"/>
265→                                                    <path id="vector (Stroke)_2" fillRule="evenodd" clipRule="evenodd" d="M9.75 12C9.75 10.7574 10.7574 9.75 12 9.75C13.2426 9.75 14.25 10.7574 14.25 12C14.25 13.2426 13.2426 14.25 12 14.25C10.7574 14.25 9.75 13.2426 9.75 12Z" fill="#000000"/>
266→                                                    <path id="vector (Stroke)_3" fillRule="evenodd" clipRule="evenodd" d="M16.75 12C16.75 10.7574 17.7574 9.75 19 9.75C20.2426 9.75 21.25 10.7574 21.25 12C21.25 13.2426 20.2426 14.25 19 14.25C17.7574 14.25 16.75 13.2426 16.75 12Z" fill="#000000"/>
267→                                                </g>
268→                                            </g>
