225→                <MoonLoader size={25} color="var(--loader-color)" loading={isLoading}/>
226→            </div>
227→        )
228→    }
229→
230→    return(
231→        <>
232→        <div ref={scrollToTop}/>
233→        <div className="notifications-container">
234→            {notifications?.map((notification) => {
235→                const isOpinion = notification?.source === 'opinion';
236→                const displayType = isOpinion
237→                    ? (notification?.type === 'mention' ? 'mention' : 'opinion_reply')
238→                    : notification?.type;
239→                const previewText = !isOpinion ? (notification?.journals?.preview_text || '') : '';
240→                const thumbnailUrl = !isOpinion ? (notification?.journals?.thumbnail_url || null) : null;
241→
242→                return(
243→                <div key={`${notification.source}-${notification.id}`} className={notification?.read ? "notification-cards" : "notification-cards-unread"}>
244→
245→                    <div className="notification-cards-child-container">
246→
247→                        <div className="notification-icon-container">
248→                            {displayType === 'reaction' ? (
249→                                <div className="notification-icon">
250→                                    <span style={{ fontSize: '26px', lineHeight: 1 }}>{getReactionEmoji(notification?.reaction_type) || '❤️'}</span>
251→                                </div>
252→                            ) : (
